DROP VIEW IF EXISTS `v_clientes_activos`;
CREATE OR REPLACE ALGORITHM=UNDEFINED SQL SECURITY INVOKER VIEW `v_clientes_activos` AS select `clientes`.`id` AS `id`,`clientes`.`nombre` AS `nombre`,`clientes`.`apellido` AS `apellido`,`clientes`.`email` AS `email`,`clientes`.`telefono` AS `telefono`,`clientes`.`tipo_documento` AS `tipo_documento`,`clientes`.`numero_documento` AS `numero_documento`,`clientes`.`direccion` AS `direccion`,`clientes`.`created_at` AS `created_at`,`clientes`.`deleted_at` AS `deleted_at` from `clientes` where (`clientes`.`deleted_at` is null);
