DROP VIEW IF EXISTS `v_ventas_validas`;
CREATE OR REPLACE ALGORITHM=UNDEFINED SQL SECURITY INVOKER VIEW `v_ventas_validas` AS select `ventas`.`id` AS `id`,`ventas`.`tienda_id` AS `tienda_id`,`ventas`.`cliente_id` AS `cliente_id`,`ventas`.`empleado_id` AS `empleado_id`,`ventas`.`caja_id` AS `caja_id`,`ventas`.`fecha` AS `fecha`,`ventas`.`subtotal` AS `subtotal`,`ventas`.`descuento` AS `descuento`,`ventas`.`impuesto` AS `impuesto`,`ventas`.`total` AS `total`,`ventas`.`estado` AS `estado`,`ventas`.`deleted_at` AS `deleted_at`,`ventas`.`created_at` AS `created_at` from `ventas` where ((`ventas`.`deleted_at` is null) and (`ventas`.`estado` <> 'anulada'));
